import{_ as n,o as a,c as e,ag as i}from"./chunks/framework.BbyMWZAR.js";const m=JSON.parse('{"title":"React commit 阶段中断后是重新开始还是继续？","description":"","frontmatter":{"title":"React commit 阶段中断后是重新开始还是继续？","difficulty":"hard","tags":["Fiber","Concurrent","render","commit","中断"],"estimate":25},"headers":[],"relativePath":"domains/react/qa/14-render-commit-interruption.md","filePath":"domains/react/qa/14-render-commit-interruption.md","lastUpdated":1783504823000}'),t={name:"domains/react/qa/14-render-commit-interruption.md"};function r(l,s,o,p,c,d){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="问答题-14-高级-react-commit-阶段中断后是重新开始还是继续" tabindex="-1">问答题 14（高级）：React commit 阶段中断后是重新开始还是继续？ <a class="header-anchor" href="#问答题-14-高级-react-commit-阶段中断后是重新开始还是继续" aria-label="Permalink to &quot;问答题 14（高级）：React commit 阶段中断后是重新开始还是继续？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>React 的并发渲染（Concurrent Rendering）把工作分为「render 阶段」和「commit 阶段」，前者可中断、可复用、可丢弃，后者不可中断。如果一次 render 已经进行到一半被打断，下次是从头开始还是继续？commit 呢？请解释背后的原理。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><h3 id="两个阶段" tabindex="-1">两个阶段 <a class="header-anchor" href="#两个阶段" aria-label="Permalink to &quot;两个阶段&quot;">​</a></h3><ul><li><strong>Render 阶段（reconciliation）</strong>：从当前 fiber 树出发，创建/更新 fiber 节点，做 diff，生成 effects list。<strong>副作用尚未落到 DOM</strong>。可以中断、暂停、放弃、重新开始。</li><li><strong>Commit 阶段</strong>：把 effects 应用到 DOM（插入、更新、删除节点，运行 <code>useLayoutEffect</code>、绑定 ref、异步跑 <code>useEffect</code>）。<strong>不可中断</strong>（跑一次同步跑到底）。</li></ul><h3 id="render-阶段-中断后重新开始-而不是继续" tabindex="-1">Render 阶段：中断后<strong>重新开始</strong>（而不是继续） <a class="header-anchor" href="#render-阶段-中断后重新开始-而不是继续" aria-label="Permalink to &quot;Render 阶段：中断后**重新开始**（而不是继续）&quot;">​</a></h3><p>React 的调度器（Scheduler）每处理完一个 fiber 节点后，检查当前时间片是否用完（例如 5ms）。用完就让出主线程（<code>MessageChannel</code> 或 <code>setTimeout(0)</code>），等浏览器处理别的高优任务（用户输入、绘制），然后继续。</p><ul><li><strong>在同一次调度内被时间片切走</strong>：不算「打断」，而是<strong>暂停 + 恢复</strong>。React 记录当前处理到哪个 fiber，下次继续处理即可。这是「切片（time-slicing）」的核心。</li><li><strong>被更高优先级更新打断</strong>：例如渲染低优先级 state 到一半，用户点击触发一个高优 state 更新。这时低优先级 render 被<strong>丢弃（discard）</strong>，React 从当前 fiber 树的<strong>根节点</strong>重新开始，用最新的 state 计算一次高优渲染；后面再回来处理低优渲染。</li><li>之所以能安全丢弃：render 阶段没有副作用（<strong>除了状态、ref 等 React 管辖的容器</strong>），丢掉不会破坏用户可见的 DOM。</li></ul><p><strong>为什么能重新开始而不出问题？</strong></p><ul><li>Render 阶段只在<strong>内存里操作 fiber 树</strong>（<code>workInProgress</code> 树，双缓冲）。</li><li>每次重新 render 会<strong>从 alternate 树（当前提交在屏的）</strong> 出发克隆，不会污染上一版本。</li><li><strong>用户可见的 DOM = current fiber 树 → 已 commit 部分</strong>。workInProgress 被丢弃时 DOM 不变。</li></ul><h3 id="commit-阶段-不可中断-一次同步跑完" tabindex="-1">Commit 阶段：<strong>不可中断，一次同步跑完</strong> <a class="header-anchor" href="#commit-阶段-不可中断-一次同步跑完" aria-label="Permalink to &quot;Commit 阶段：**不可中断，一次同步跑完**&quot;">​</a></h3><ul><li>Commit 涉及 DOM 变动、ref 绑定、layout effect 同步跑，中断会导致<strong>部分 DOM 更新可见</strong>（撕裂 tearing）。</li><li>Commit 的操作都是同步、快速的（React 在 render 阶段已经把「要干什么」计算完了，commit 只是执行）。</li><li>期间用户不能与页面交互（浏览器主线程被占用），但一般 commit 很快（几毫秒），感知不到卡顿。</li><li>如果 commit 慢（比如 DOM 巨大），才是真正的卡顿点。此时优化点是<strong>减少要 commit 的节点数</strong>，或考虑虚拟列表。</li></ul><h3 id="effects-的时机" tabindex="-1">Effects 的时机 <a class="header-anchor" href="#effects-的时机" aria-label="Permalink to &quot;Effects 的时机&quot;">​</a></h3><ul><li><strong>useLayoutEffect</strong>：commit 阶段同步执行，DOM 已更新但<strong>尚未绘制</strong>。用于需要「读 DOM 尺寸 + 立即修改」的场景。</li><li><strong>useEffect</strong>：commit 完成、浏览器完成绘制后，异步执行（<code>MessageChannel</code> 调度）。<strong>不阻塞绘制</strong>。</li></ul><h3 id="图示" tabindex="-1">图示 <a class="header-anchor" href="#图示" aria-label="Permalink to &quot;图示&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>调度器 loop:</span></span>
<span class="line"><span>  ┌─────────────────────────────────────┐</span></span>
<span class="line"><span>  │        Render (可中断)                │</span></span>
<span class="line"><span>  │  ┌───┐ ┌───┐ ┌───┐                 │</span></span>
<span class="line"><span>  │  │f1 │→│f2 │→│f3 │ ...              │</span></span>
<span class="line"><span>  │  └───┘ └───┘ └───┘                 │</span></span>
<span class="line"><span>  │  时间片用完 → 让出 → 恢复            │</span></span>
<span class="line"><span>  │  高优打断 → 丢弃 → 重新开始           │</span></span>
<span class="line"><span>  └─────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ↓ workInProgress tree 完成</span></span>
<span class="line"><span>  ┌─────────────────────────────────────┐</span></span>
<span class="line"><span>  │        Commit (不可中断)              │</span></span>
<span class="line"><span>  │  Before mutation → Mutation → Layout │</span></span>
<span class="line"><span>  │  DOM 更新 + layoutEffect + ref       │</span></span>
<span class="line"><span>  └─────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ↓ 浏览器绘制</span></span>
<span class="line"><span>  ┌─────────────────────────────────────┐</span></span>
<span class="line"><span>  │        Passive Effects              │</span></span>
<span class="line"><span>  │  useEffect 异步执行                  │</span></span>
<span class="line"><span>  └─────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h2 id="追问-1-render-阶段可中断-是不是意味着函数组件可能被执行多次-副作用要注意什么" tabindex="-1">追问 1：Render 阶段可中断，是不是意味着<strong>函数组件可能被执行多次</strong>？副作用要注意什么？ <a class="header-anchor" href="#追问-1-render-阶段可中断-是不是意味着函数组件可能被执行多次-副作用要注意什么" aria-label="Permalink to &quot;追问 1：Render 阶段可中断，是不是意味着**函数组件可能被执行多次**？副作用要注意什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>是的</strong>。同一次更新如果被更高优打断，render 阶段可能重跑，函数组件会执行多次；useState / useReducer 会得到一致的结果（因为 state 存在 fiber 上，重跑时从同一份 state 起算）。</li><li>副作用位置要点： <ol><li><strong>不要在函数组件顶层写有副作用的代码</strong>（<code>fetch</code>、修改外部变量、<code>document.title = ...</code>）。这些应放到 <code>useEffect</code> 里，只在 commit 后跑。</li><li><strong>不要在 render 里读 / 改 ref</strong>，可能拿到中间态，或改动被丢弃时不一致。</li><li><strong>useMemo / useState 的初始化函数应是纯的</strong>。React 未来可能会在开发模式下故意重跑一次以暴露副作用问题（Strict Mode 已经在做类似事情）。</li></ol></li><li>严格模式（<code>&lt;React.StrictMode&gt;</code>）下 React 会<strong>故意双调用</strong>组件函数、setState 初始化函数、useMemo 计算函数，就是为了帮开发者检测这类隐藏的副作用。</li></ul><h2 id="追问-2-什么样的更新会被视为「高优先级」-如何主动降级" tabindex="-1">追问 2：什么样的更新会被视为「高优先级」？如何主动降级？ <a class="header-anchor" href="#追问-2-什么样的更新会被视为「高优先级」-如何主动降级" aria-label="Permalink to &quot;追问 2：什么样的更新会被视为「高优先级」？如何主动降级？&quot;">​</a></h2><p><strong>答</strong>：React 内部有一套「lanes」优先级模型（简化理解）：</p><ul><li><strong>高优先级（同步）</strong>：用户输入类（click、input、focus）、<code>flushSync</code> 内的更新。UI 必须立刻响应。</li><li><strong>默认</strong>：普通 setState。</li><li><strong>低优先级 / Transition</strong>：<code>useTransition</code> / <code>startTransition</code> 包裹的更新。可被高优先级中断。</li><li><strong>Idle</strong>：仅在空闲时执行。</li></ul><p>用户主动降级：</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">isPending</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">startTransition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useTransition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> handleChange</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  setInput</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(e.target.value); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 高优，立刻更新输入框</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  startTransition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    setFilteredList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">computeList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(e.target.value)); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 低优，可打断</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li>场景：输入 + 高开销联动（列表过滤、图表重绘）。<strong>输入框要立刻响应，列表可以稍慢</strong>。</li><li>类似地 <code>useDeferredValue(value)</code> 返回一个「延迟版本」的值，用它做重计算，React 会在合适时机推进它。</li></ul><h2 id="追问-3-为什么-concurrent-模式设计成「render-可中断、commit-不可中断」-如果-commit-也可中断会怎么样" tabindex="-1">追问 3：为什么 Concurrent 模式设计成「render 可中断、commit 不可中断」？如果 commit 也可中断会怎么样？ <a class="header-anchor" href="#追问-3-为什么-concurrent-模式设计成「render-可中断、commit-不可中断」-如果-commit-也可中断会怎么样" aria-label="Permalink to &quot;追问 3：为什么 Concurrent 模式设计成「render 可中断、commit 不可中断」？如果 commit 也可中断会怎么样？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>不可中断的核心原因是保证 DOM 一致性</strong>。commit 若可中断，用户可能看到「一半更新的 UI」（tearing）——比如列表 5 项本要一次性更新，中断后 3 项已更新、2 项还没更新，视觉上就错乱了。</li><li>假设允许中断 commit： <ol><li>需要一个「回滚 DOM」的机制，即所谓 DOM 事务。原生 DOM 不支持事务，React 得手动记录所有修改，回滚时反向操作，成本极大。</li><li>中断点无法安全定义：某些 DOM 更新会触发同步的 layout 计算（读取 offsetTop 之类），暂停后再继续会得到不一致的中间态。</li><li>useLayoutEffect 期望「DOM 已完全更新」，中断后跑 layoutEffect 会读到半成品 DOM，破坏用户预期。</li></ol></li><li><strong>实践中的权衡</strong>：render 阶段占大多数时间（构建 vdom、diff），把它拆分成时间片就足够解决大部分卡顿；commit 阶段一般很快（毫秒级），保持同步简化了一致性保证，是最优折衷。</li><li>类似的思想在其他系统里也有：<strong>准备阶段（可撤销）与提交阶段（不可撤销）</strong> 分离，是<strong>事务处理</strong>的经典模式。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/render-and-commit" target="_blank" rel="noreferrer">React: Render and Commit</a>：render 可丢弃与 commit 同步提交的原子性</li><li><a href="https://react.dev/blog/2022/03/29/react-v18" target="_blank" rel="noreferrer">React 18 Blog</a>：并发渲染中时间片调度与优先级抢占</li><li><a href="https://react.dev/reference/react/useTransition" target="_blank" rel="noreferrer">React: useTransition</a>：被打断后如何保留旧 UI 直至新树就绪</li></ul>`,32)])])}const g=n(t,[["render",r]]);export{m as __pageData,g as default};
